// 假定获取输入的query对象
let inputQuery = $input.all()[0].json.query;

// 从输入对象中读取开始日期
let activeDate_Start = inputQuery.ActiveDate_Start;
let activeDate_End = inputQuery.ActiveDate_End;

// 获取当前日期
let currentDate = new Date();

// 将字符串日期转换为Date对象
let startDate = new Date(activeDate_Start);
let endDate = currentDate; // 使用当前日期作为截止日期

// 将每月的时间段存储到categories和timeIntervals中
let categories = [];
let timeIntervals = [];

while (startDate < endDate) {
  // 当前处理的月份的年月
  let year = startDate.getFullYear();
  let month = (startDate.getMonth() + 1).toString().padStart(2, '0'); // 格式化月为两位数

  // 计算本月的结束日期
  let endOfMonth = new Date(year, startDate.getMonth() + 1, 0);

  // 如果本月结束日期超过了endDate，则使用endDate
  if (endOfMonth > endDate) {
    endOfMonth = endDate;
  }

  // 添加到categories的显示月份,包含年份
  let category = `${year}年${month}月`;
  categories.push(category);

  // 创建时间段,格式[开始时间, 结束时间]
  timeIntervals.push([
    startDate.toISOString().split('T')[0], // 当前月份的开始日期
    endOfMonth.toISOString().split('T')[0] // 当前月份的结束日期
  ]);

  // 更新下一个区间的开始日期
  startDate = new Date(year, startDate.getMonth() + 1, 1);
}

// 获取国家列表
let countries = JSON.parse(inputQuery.Country);

// 存储最终的查询参数列表
let queryList = [];

// 定义国家映射
const countryMapping = {
  "Overseas": ["US", "EU"]
};

// 对每个国家生成一个查询参数对象
for (let country of countries) {
  let mappedCountries = countryMapping[country] || [country]; // 如果为 "Overseas"，则转化为 ["US", "EU"]

  for (let mappedCountry of mappedCountries) {
    let query = {
      ...inputQuery, // 原查询参数
      "categories": categories,
      "timeIntervals": timeIntervals,
      "Country": mappedCountry
    };
    queryList.push(query);
  }
}

// 输出结果
return queryList;

// 获取唯一的categories值
const categoriesSet = new Set($input.all().map(item => item.json.categories[0]));
const categoriesData = Array.from(categoriesSet).sort();

// 构建包含国家和对应数据的对象
const countryMap = new Map();
$input.all().forEach(item => {
  const country = item.json.Country;
  const category = item.json.categories[0];
  const count = parseInt(item.json.count);

  if (!countryMap.has(country)) {
    countryMap.set(country, Array(categoriesData.length).fill(0));
  }

  const index = categoriesData.indexOf(category);
  countryMap.get(country)[index] = count;
});

// 生成最终的数据结构
let result = Array.from(countryMap, ([name, data]) => ({ name, data }));

// 整合EU和US为Overseas
let overseasData = Array(categoriesData.length).fill(0);
let totalActiveOverseas = 0;

result = result.filter(item => {
  if (item.name === 'EU' || item.name === 'US') {
    overseasData = overseasData.map((val, idx) => val + item.data[idx]);
    totalActiveOverseas += item.TotalActive || 0; // take TotalActive from item
    return false; // 过滤掉EU和US
  }
  return true;
});

result.push({ name: 'Overseas', data: overseasData, TotalActive: totalActiveOverseas });

// 将TotalActive放到result中
const totalActiveMap = new Map($('判断查询结果').all().map(item => [item.json.country_code, parseInt(item.json.count)]));
result.forEach(item => {
  if (totalActiveMap.has(item.name)) {
    item.TotalActive = totalActiveMap.get(item.name);
  }
});

// 更新Overseas的TotalActive
const totalActiveOverseasFromMap = totalActiveMap.get('EU') + totalActiveMap.get('US');
const overseasItem = result.find(item => item.name === 'Overseas');
if (overseasItem) {
  overseasItem.TotalActive = totalActiveOverseasFromMap;
}

return {
  result: result,
  categoriesData: categoriesData
};

