const countries = $('划分时间区间').all().map(item => item.json.Country);
const timeIntervals = $('划分时间区间').all()[0].json.timeIntervals;
const categories = $('划分时间区间').all()[0].json.categories;
const List = countries.flatMap((country, countryIndex) => {
  return timeIntervals.map((interval, intervalIndex) => {
    return {
      Country: country,
      ActiveDate_End: $('划分时间区间').all()[countryIndex].json.ActiveDate_End,
      ActiveDate_Start: $('划分时间区间').all()[countryIndex].json.ActiveDate_Start,
      categories: [categories[intervalIndex]],
      timeIntervals: [interval]
    };
  });
});

return List;
